import{_ as l,o as a,c as r,ae as e}from"./chunks/framework.DAK3ioSj.js";const S=JSON.parse('{"title":"Skill 评测（Evaluation）","description":"","frontmatter":{},"headers":[],"relativePath":"radar/category-04-evaluation.md","filePath":"radar/category-04-evaluation.md"}'),o={name:"radar/category-04-evaluation.md"};function i(s,t,n,d,h,k){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="skill-评测-evaluation" tabindex="-1">Skill 评测（Evaluation） <a class="header-anchor" href="#skill-评测-evaluation" aria-label="Permalink to &quot;Skill 评测（Evaluation）&quot;">​</a></h1><blockquote><p><strong>成熟度</strong>: 🟡 成长期 · <strong>综合评分</strong>: <strong>0.47</strong></p><p><strong>业界判断</strong>：SkillsBench 提供事实标准、SkillNet 5 维评分有效、<strong>SkillRet 17,810 Skill 检索 benchmark 上线</strong>，但全部仍是<strong>结果评测</strong> —— <strong>过程评测和多 Skill 归因仍是结构性缺口</strong>。</p></blockquote><hr><h2 id="业界代表产品" tabindex="-1">业界代表产品 <a class="header-anchor" href="#业界代表产品" aria-label="Permalink to &quot;业界代表产品&quot;">​</a></h2><table tabindex="0"><thead><tr><th>产品</th><th>来源</th><th>核心路径</th><th>关键数字</th></tr></thead><tbody><tr><td><a href="./tech-skillsbench.html">SkillsBench</a></td><td>学术 (1.2K+ ★)</td><td>三条件对比（无 / 编写 / 自生成）</td><td><strong>7,308 轨迹 / 84 任务 / 11 领域，+16.2pp</strong></td></tr><tr><td><a href="./tech-skillnet.html">SkillNet (5 维评分)</a></td><td>浙大 NLP (735 ★)</td><td>5 维内在质量评估</td><td>ALFWorld +40% reward, -30% 步骤</td></tr><tr><td><a href="./tech-evoskills.html">EvoSkills (Surrogate Verifier)</a></td><td>学术</td><td>主动生成测试断言 + 失败诊断</td><td>去掉 Surrogate 通过率从 71.1% 跌至 41.1%</td></tr><tr><td><a href="./tech-skillforge.html">SkillForge (Diagnostician)</a></td><td>工业研究 (SIGIR 2026)</td><td>失败追溯回 Skill 缺陷</td><td>1,883 工单 + 5 场景</td></tr><tr><td><a href="./tech-skillret.html">SkillRet</a></td><td>学术</td><td>Skill 检索大规模 benchmark</td><td><strong>17,810 Skill / 63K 训练 / 5K 评测，NDCG@10 +13.1</strong></td></tr></tbody></table><hr><h2 id="skillsbench-揭示的反共识结论" tabindex="-1">SkillsBench 揭示的反共识结论 <a class="header-anchor" href="#skillsbench-揭示的反共识结论" aria-label="Permalink to &quot;SkillsBench 揭示的反共识结论&quot;">​</a></h2><table tabindex="0"><thead><tr><th>发现</th><th>数据</th></tr></thead><tbody><tr><td>精心编写的 Skill 显著有效</td><td>平均 +16.2pp</td></tr><tr><td><strong>但领域差异 10×</strong></td><td>软件工程 +4.5pp / 医疗 +51.9pp</td></tr><tr><td><strong>自生成 Skill 平均无增益</strong></td><td>学生自己写复习笔记帮不了自己</td></tr><tr><td><strong>16/84 出现负增益</strong></td><td>加 Skill 反而更差</td></tr><tr><td><strong>聚焦优于全面</strong></td><td>2-3 模块精简 &gt; 长篇文档</td></tr></tbody></table><hr><h2 id="行业核心痛点" tabindex="-1">行业核心痛点 <a class="header-anchor" href="#行业核心痛点" aria-label="Permalink to &quot;行业核心痛点&quot;">​</a></h2><h3 id="🔴-领域-skill-评测数据集构建困难" tabindex="-1">🔴 领域 Skill 评测数据集构建困难 <a class="header-anchor" href="#🔴-领域-skill-评测数据集构建困难" aria-label="Permalink to &quot;🔴 领域 Skill 评测数据集构建困难&quot;">​</a></h3><p>SkillsBench 的 84 个确定性验证器都是<strong>手工编写的</strong>，覆盖 11 个领域。但 SkillNet 上有 <strong>200K+ Skill 横跨数百个领域</strong> —— 绝大多数没有评测基础设施。EvoSkills 的 Surrogate Verifier 是替代方案，但<strong>判断能力上限 = LLM 自身的领域知识</strong>（对运维、医疗、法律等专业场景不够）。SkillRet 给召回评测提供了 17,810 Skill 的标准化套件，但<strong>针对路由本身，不评测 task success rate</strong>。</p><h3 id="🔴-过程遵从度评测完全空白" tabindex="-1">🔴 过程遵从度评测完全空白 <a class="header-anchor" href="#🔴-过程遵从度评测完全空白" aria-label="Permalink to &quot;🔴 过程遵从度评测完全空白&quot;">​</a></h3><p>Agent 把任务做对了，但<strong>完全没按 Skill 说的来</strong> —— 到底是 Skill 有用还是模型自己就能做？所有评测都是<strong>结果导向的黑盒</strong>，只看 pass/fail，<strong>不看 Agent 是否遵从了 Skill 定义的流程</strong>。</p><p>这直接导致三个下游问题无法解决：</p><ul><li>无法区分&quot;Skill 有效&quot;和&quot;模型本身就能做&quot;</li><li>无法定位 16/84 负增益的根因</li><li>多 Skill 场景下无法归因单个 Skill 的贡献</li></ul><h3 id="🔴-自生成-skill-几乎没用" tabindex="-1">🔴 自生成 Skill 几乎没用 <a class="header-anchor" href="#🔴-自生成-skill-几乎没用" aria-label="Permalink to &quot;🔴 自生成 Skill 几乎没用&quot;">​</a></h3><p>策划 Skill +16.2pp，自生成 ≈ 0pp —— 模型能消费高质量 Skill 但<strong>无法一次性自创等质量内容</strong>。EvoSkill / EvoSkills / Trace2Skill 用迭代生成缓解，但 SkillsBench 揭示的&quot;单次自生成的根本限制&quot;仍成立。</p><h3 id="🟢-skill-内在质量评估-基本已解" tabindex="-1">🟢 Skill 内在质量评估（基本已解） <a class="header-anchor" href="#🟢-skill-内在质量评估-基本已解" aria-label="Permalink to &quot;🟢 Skill 内在质量评估（基本已解）&quot;">​</a></h3><p>SkillNet 5 维评分（安全 / 完整 / 可执行 / 可维护 / 成本）在三个环境验证有效。<strong>但评估的是&quot;写得好不好&quot;而非&quot;在特定场景有没有效&quot;</strong> —— 后者仍开放。</p><h3 id="⚪-多-skill-协同归因" tabindex="-1">⚪ 多 Skill 协同归因 <a class="header-anchor" href="#⚪-多-skill-协同归因" aria-label="Permalink to &quot;⚪ 多 Skill 协同归因&quot;">​</a></h3><p>任务同时用了三个 Skill，效果差，<strong>不知道该改哪个</strong> —— 只能逐个禁用手动排查。<strong>无消融实验设计方法论</strong>，但机器学习领域的 SHAP/Shapley 值可以作为迁移的理论基础。</p>',22)])])}const c=l(o,[["render",i]]);export{S as __pageData,c as default};
